    """Resolve options whose ``default`` is a dynamic mapping of other
    option declarations to value-to-default lookups, now that command
    line arguments, environment variables, and configuration files have
    all been processed.

    Only options whose value still comes from :attr:`ParameterSource.DEFAULT`
    are affected. If multiple source options are given, later entries take
    precedence over earlier ones. If nothing matches, the option is left
    as ``None``.
    """
    params = ctx.command.get_params(ctx)

    for param in params:
        if not isinstance(param, Option) or not isinstance(param.default, dict):
            continue

        if ctx.get_parameter_source(param.name) is not ParameterSource.DEFAULT:
            continue

        resolved = None

        for source_decl, value_map in param.default.items():
            source_param = next(
                (
                    p
                    for p in params
                    if source_decl in p.opts or source_decl in p.secondary_opts
                ),
                None,
            )

            if source_param is None or source_param.name is None:
                continue

            source_value = ctx.params.get(source_param.name)

            if str(source_value) in value_map:
                resolved = value_map[str(source_value)]

        if resolved is not None:
            ctx.params[param.name] = param.type_cast_value(ctx, resolved)


